#include <stdio.h>
#include <cuda.h>

struct Node
{
    int starting;
    int no_of_edges;
};

__global__ void bfs_first_kernel(Node* d_graph_nodes, bool* d_graph_mask, int* d_graph_edges, 
                                  bool* d_graph_visited, bool* d_updating_graph_mask, 
                                  int* d_cost, int no_of_nodes)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;

    if(tid < no_of_nodes)
    {
        if(d_graph_mask[tid] == true)
        { 
            d_graph_mask[tid] = false;
            for(int i = d_graph_nodes[tid].starting; 
                (d_graph_nodes[tid].no_of_edges + d_graph_nodes[tid].starting) > i; i++)
            {
                int id = d_graph_edges[i];
                if(!d_graph_visited[id])
                {
                    d_cost[id] = d_cost[tid] + 1;
                    d_updating_graph_mask[id] = true;
                }
            }
        }
    }
}

__global__ void bfs_second_kernel(bool* d_graph_mask, bool* d_updating_graph_mask, 
                                   bool* d_graph_visited, int* d_cost, 
                                   int no_of_nodes, bool* d_stop)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;

    if(tid < no_of_nodes)
    {
        if(d_updating_graph_mask[tid] == true)
        {
            d_graph_mask[tid] = true;
            d_graph_visited[tid] = true;
            *d_stop = true;
            d_updating_graph_mask[tid] = false;
        }
    }
}

